def get_weights(conn: sqlite3.Connection) -> dict[str, float]:
    """metric_name → weight の辞書を返す（未設定メトリクスは 1.0）"""
    rows = conn.execute("SELECT metric_name, weight FROM weight_config").fetchall()
    return {r["metric_name"]: r["weight"] for r in rows}


def set_weights(db_path: Path, weights: dict[str, float]) -> None:
    """重みを一括保存（INSERT OR REPLACE）"""
    updated_at = datetime.now(timezone.utc).isoformat()
    with get_db(db_path) as conn:
        for metric, w in weights.items():
            conn.execute(
                "INSERT OR REPLACE INTO weight_config (metric_name, weight, updated_at) VALUES (?, ?, ?)",
                (metric, w, updated_at),
            )
        conn.commit()


def _migrate_all_columns(db_path: Path | None = None) -> None:
    """全バージョン間のカラム追加マイグレーションを実行する（べき等）。"""
    if db_path is None:
        db_path = get_db_path()
    with get_db(db_path) as conn:
        # runs テーブル
        runs_cols = {row[1] for row in conn.execute("PRAGMA table_info(runs)").fetchall()}
        if "model_digest" not in runs_cols:
            conn.execute("ALTER TABLE runs ADD COLUMN model_digest TEXT")

        # results テーブル
        results_cols = {row[1] for row in conn.execute("PRAGMA table_info(results)").fetchall()}
        if "score_stderr" not in results_cols:
            conn.execute("ALTER TABLE results ADD COLUMN score_stderr REAL")
        if "score_judge" not in results_cols:
            conn.execute("ALTER TABLE results ADD COLUMN score_judge REAL")

        # tasks テーブル
        tasks_cols = {row[1] for row in conn.execute("PRAGMA table_info(tasks)").fetchall()}
        for col, coltype in [
            ("timeout", "INTEGER"),
            ("api_max_retry", "INTEGER"),
            ("api_retry_sleep", "INTEGER"),
        ]:
            if col not in tasks_cols:
                conn.execute(f"ALTER TABLE tasks ADD COLUMN {col} {coltype}")

        conn.commit()


def migrate_add_score_judge(db_path: Path | None = None) -> None:
    """後方互換のため残存。_migrate_all_columns を呼び出す。"""
    _migrate_all_columns(db_path)


def upsert_result_judge(
    db_path: Path,
    run_id: str,
    dataset: str,
    metric_name: str,
    score_judge: float | None,
) -> None:
    """既存 results レコードの score_judge を更新する。"""
    with get_db(db_path) as conn:
        conn.execute(
            """
            UPDATE results
            SET score_judge = ?
            WHERE run_id = ? AND dataset = ? AND metric_name = ?
            """,
            (score_judge, run_id, dataset, metric_name),
        )
        conn.commit()
